local UI_Utils = {}

function UI_Utils.addCorner(parent: GuiObject, radius: number?)
    local c = Instance.new(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'*************************************************************************************','*************************************************************************','*******************************************************************','***************************************************************************************************************','******************************************************************************************************************','**************************************************************************************************************','*****************************************************************************************************','******************************************************************************************************************'}))
    c.CornerRadius = UDim.new(0, radius or Theme.Sizes.CornerRadius)
    c.Parent = parent
    return c
end

function UI_Utils.addStroke(parent: GuiObject, color: Color3?, thickness: number?)
    local s = Instance.new(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'*************************************************************************************','*************************************************************************','***********************************************************************************','********************************************************************************************************************','******************************************************************************************************************','***************************************************************************************************************','***********************************************************************************************************','*****************************************************************************************************'}))
    s.Color = color or Theme.Colors.border
    s.Thickness = thickness or Theme.Sizes.StrokeThickness
    s.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
    s.Parent = parent
    return s
end

function UI_Utils.makeTween(obj: Instance, props: {[string]: any}, dur: number?, style: Enum.EasingStyle?, dir: Enum.EasingDirection?)
    return TweenService:Create(obj,
        TweenInfo.new(dur or 0.18, style or Enum.EasingStyle.Quart, dir or Enum.EasingDirection.Out),
        props)
end

function UI_Utils.hoverEffect(btn: GuiButton, normalColor: Color3?, hoverColor: Color3?)
    btn.MouseEnter:Connect(function()
        UI_Utils.makeTween(btn, {BackgroundColor3 = hoverColor or Theme.Colors.cardHover}, 0.15):Play()
    end)
    btn.MouseLeave:Connect(function()
        UI_Utils.makeTween(btn, {BackgroundColor3 = normalColor or Theme.Colors.card}, 0.15):Play()
    end)
end

function UI_Utils.makeToggleBtn(parent: GuiObject, text: string, yPosition: number, callback: (boolean) -> (), initialState: boolean?)
    local card = Instance.new(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'**********************************************************************','******************************************************************************************************************','*************************************************************************************************','*************************************************************************************************************','*****************************************************************************************************'}))
