    local toggleFrame = Instance.new(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'**********************************************************************','******************************************************************************************************************','*************************************************************************************************','*************************************************************************************************************','*****************************************************************************************************'}))
    toggleFrame.Size = UDim2.new(0, 40, 0, 24)
    toggleFrame.Position = UDim2.new(1, -50, 0.5, -12)
    toggleFrame.BackgroundColor3 = Theme.Colors.red
    toggleFrame.BorderSizePixel = 0
    toggleFrame.Parent = card
    UI_Utils.addCorner(toggleFrame, 999)

    local toggleCircle = Instance.new(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'**********************************************************************','******************************************************************************************************************','*************************************************************************************************','*************************************************************************************************************','*****************************************************************************************************'}))
    toggleCircle.Size = UDim2.new(0, 20, 0, 20)
    toggleCircle.Position = UDim2.new(0, 2, 0.5, -10)
    toggleCircle.BackgroundColor3 = Theme.Colors.text
    toggleCircle.BorderSizePixel = 0
    toggleCircle.Parent = toggleFrame
    UI_Utils.addCorner(toggleCircle, 999)

    local isOn = initialState or false

    local function updateToggleUI()
        if isOn then
            UI_Utils.makeTween(toggleFrame, {BackgroundColor3 = Theme.Colors.green}, 0.2):Play()
            UI_Utils.makeTween(toggleCircle, {Position = UDim2.new(1, -22, 0.5, -10)}, 0.2):Play()
        else
            UI_Utils.makeTween(toggleFrame, {BackgroundColor3 = Theme.Colors.red}, 0.2):Play()
            UI_Utils.makeTween(toggleCircle, {Position = UDim2.new(0, 2, 0.5, -10)}, 0.2):Play()
        end
    end

    updateToggleUI()

    local btn = Instance.new(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'************************************************************************************','*****************************************************************************************************','************************************************************************************************************************','********************************************************************************************************************','******************************************************************','*********************************************************************************************************************','********************************************************************************************************************','********************************************************************************************************************','***************************************************************************************************************','**************************************************************************************************************'}))
    btn.Text = jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({})
    btn.Size = UDim2.new(1, 0, 1, 0)
    btn.BackgroundTransparency = 1
    btn.Parent = card
    UI_Utils.hoverEffect(btn, Theme.Colors.card, Theme.Colors.cardHover)

    btn.MouseButton1Click:Connect(function()
        isOn = not isOn
        updateToggleUI()
        if callback then callback(isOn) end
    end)

    return card, function(state) isOn = state; updateToggleUI() end
end

function UI_Utils.makeSlider(parent: GuiObject, yPosition: number, text: string, initialValue: number, minValue: number, maxValue: number, callback: (number) -> ())
    local card = Instance.new(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'**********************************************************************','******************************************************************************************************************','*************************************************************************************************','*************************************************************************************************************','*****************************************************************************************************'}))
    card.Size = UDim2.new(1, -40, 0, 60)
    card.Position = UDim2.new(0, 20, 0, yPosition)
    card.BackgroundColor3 = Theme.Colors.card
    card.BorderSizePixel = 0
    card.Parent = parent
    UI_Utils.addCorner(card)
    UI_Utils.addStroke(card)

    local label = Instance.new(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'************************************************************************************','*****************************************************************************************************','************************************************************************************************************************','********************************************************************************************************************','****************************************************************************','*************************************************************************************************','**************************************************************************************************','*****************************************************************************************************','************************************************************************************************************'}))
    label.Text = text .. jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'**********************************************************','********************************'}) .. string.format(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'*************************************','**********************************************','*************************************************','******************************************************************************************************'}), initialValue)
    label.Size = UDim2.new(1, -20, 0, 20)
    label.Position = UDim2.new(0, 10, 0, 5)
    label.BackgroundTransparency = 1
    label.TextColor3 = Theme.Colors.text
    label.Font = Theme.Fonts.Body
    label.TextSize = Theme.Sizes.TextMedium
    label.TextXAlignment = Enum.TextXAlignment.Left
    label.Parent = card

    local sliderFrame = Instance.new(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'**********************************************************************','******************************************************************************************************************','*************************************************************************************************','*************************************************************************************************************','*****************************************************************************************************'}))
    sliderFrame.Size = UDim2.new(1, -20, 0, 8)
    sliderFrame.Position = UDim2.new(0, 10, 0, 30)
    sliderFrame.BackgroundColor3 = Theme.Colors.subText
    sliderFrame.BorderSizePixel = 0
    sliderFrame.Parent = card
    UI_Utils.addCorner(sliderFrame, 4)

    local sliderFill = Instance.new(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'**********************************************************************','******************************************************************************************************************','*************************************************************************************************','*************************************************************************************************************','*****************************************************************************************************'}))
    sliderFill.Size = UDim2.new((initialValue - minValue) / (maxValue - minValue), 0, 1, 0)
    sliderFill.BackgroundColor3 = Theme.Colors.accent
    sliderFill.BorderSizePixel = 0
    sliderFill.Parent = sliderFrame
    UI_Utils.addCorner(sliderFill, 4)

    local sliderHandle = Instance.new(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'**********************************************************************','******************************************************************************************************************','*************************************************************************************************','*************************************************************************************************************','*****************************************************************************************************'}))
    sliderHandle.Size = UDim2.new(0, 16, 0, 16)
    sliderHandle.Position = UDim2.new((initialValue - minValue) / (maxValue - minValue), -8, 0.5, -8)
    sliderHandle.BackgroundColor3 = Theme.Colors.accentGlow
    sliderHandle.BorderSizePixel = 0
    sliderHandle.Parent = sliderFrame
    UI_Utils.addCorner(sliderHandle, 999)
    UI_Utils.addStroke(sliderHandle, Theme.Colors.accentDim, 2)

    local currentValue = initialValue
    local isDragging = false

    local function updateSlider(inputPosition: Vector2)
        local relativeX = math.clamp(inputPosition.X - sliderFrame.AbsolutePosition.X, 0, sliderFrame.AbsoluteSize.X)
        local percentage = relativeX / sliderFrame.AbsoluteSize.X
        currentValue = minValue + percentage * (maxValue - minValue)
        currentValue = math.round(currentValue * 10) / 10

        sliderFill.Size = UDim2.new(percentage, 0, 1, 0)
        sliderHandle.Position = UDim2.new(percentage, -8, 0.5, -8)
        label.Text = text .. jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'**********************************************************','********************************'}) .. string.format(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'*************************************','**********************************************','*************************************************','******************************************************************************************************'}), currentValue)
        if callback then callback(currentValue) end
    end

    sliderHandle.InputBegan:Connect(function(input: InputObject)
        if input.UserInputType == Enum.UserInputType.MouseButton1 then
            isDragging = true
            input:Capture()
        end
    end)

    UserInputService.InputChanged:Connect(function(input: InputObject)
        if isDragging and input.UserInputType == Enum.UserInputType.MouseMovement then
            updateSlider(input.Position)
        end
    end)

    UserInputService.InputEnded:Connect(function(input: InputObject)
        if input.UserInputType == Enum.UserInputType.MouseButton1 then
            isDragging = false
        end
    end)

    sliderFrame.InputBegan:Connect(function(input: InputObject)
        if input.UserInputType == Enum.UserInputType.MouseButton1 then
            updateSlider(input.Position)
            isDragging = true
            input:Capture()
        end
    end)

    return card, function(value: number) currentValue = value; updateSlider(Vector2.new(sliderFrame.AbsolutePosition.X + (value - minValue) / (maxValue - minValue) * sliderFrame.AbsoluteSize.X, 0)) end
end

