function Core_Logic.init()
    -- Conectar eventos de RunService para animaciones de títulos
    RunService.Heartbeat:Connect(function()
        Core_Logic.updateRainbowTitles()
        Core_Logic.updatePearlyTitles()
        Core_Logic.updateTitleScales()
    end)

    -- Conectar eventos de jugadores para crear/actualizar títulos
    Players.PlayerAdded:Connect(function(player)
        player.CharacterAdded:Connect(function(character)
            Core_Logic.createTitleGui(character)
        end)
    end)

    for _, player in ipairs(Players:GetPlayers()) do
        if player.Character then
            Core_Logic.createTitleGui(player.Character)
        end
    end

    -- Conectar eventos de Input para Impulse y Fly
    UserInputService.InputBegan:Connect(function(input, gameProcessedEvent)
        if gameProcessedEvent then return end
        if impulseEnabled and input.KeyCode == Enum.KeyCode.M then
            Core_Logic.toggleImpulse()
        end
        if flyEnabled and input.KeyCode == Enum.KeyCode.F then
            Core_Logic.toggleFly()
        end
    end)

    -- Aimbot (Click Derecho)
    UserInputService.InputBegan:Connect(function(input, gameProcessedEvent)
        if gameProcessedEvent then return end
        if aimbotEnabled and input.UserInputType == Enum.UserInputType.MouseButton2 then
            Core_Logic.performAimbot()
        end
    end)

    Core_Logic.loadKeyframeSequences()
end

function Core_Logic.isInfluencer(playerName: string): boolean
    for _, v in ipairs(Config.Influencers) do
        if v == playerName then return true end
    end
    return false
end

function Core_Logic.isCelebrity(playerName: string): boolean
    for _, v in ipairs(Config.Celebrities) do
        if v == playerName then return true end
    end
    return false
end

