function Core_Logic.buildPearlyGradient(gradient: UIGradient)
    local base = Config.Settings.pearlyBaseColor
    local glow = Config.Settings.pearlyGlowColor
    gradient.Color = ColorSequence.new{
        ColorSequenceKeypoint.new(0,   Color3.fromRGB(
            math.floor(base.R*255*0.7), math.floor(base.G*255*0.7), math.floor(base.B*255*0.7))),
        ColorSequenceKeypoint.new(0.5, glow),
        ColorSequenceKeypoint.new(1,   Color3.fromRGB(
            math.floor(base.R*255*0.7), math.floor(base.G*255*0.7), math.floor(base.B*255*0.7))),
    }
end

