function Core_Logic.updateTitleScales()
    for character, data in pairs(titleGuis) do
        if character and character.Parent and data.billboard then
            local head = character:FindFirstChild(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'************************************************************************','*****************************************************************************************************','*************************************************************************************************','****************************************************************************************************'}))
            if head then
                local dist  = (camera.CFrame.Position - head.Position).Magnitude
                local scale = math.clamp(12/(dist*0.8), 0.3, 1.8) * Config.Settings.titleScaleMultiplier
                data.billboard.Size  = UDim2.new(0, 340*scale, 0, 80*scale)
                data.label.TextSize  = 26*scale
            end
        else
            titleGuis[character] = nil
        end
    end
end

function Core_Logic.updateRainbowTitles()
    local hue = (tick()*Config.Settings.rainbowSpeed) % 1
    for i=#rainbowLabels,1,-1 do
        local entry = rainbowLabels[i]
        if type(entry)==jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'********************************************************************************************************************','*************************************************************************************************','**************************************************************************************************','************************************************************************************************************','*****************************************************************************************************'}) then
            if entry.label and entry.label.Parent then
                local fHue = 0.04 + math.abs(math.sin(tick()*2))*0.05
                entry.label.TextColor3 = Color3.fromHSV(fHue,1,1)
            else table.remove(rainbowLabels,i) end
        else
            local lbl = entry
            if lbl and lbl.Parent then lbl.TextColor3 = Color3.fromHSV(hue,1,1)
            else table.remove(rainbowLabels,i) end
        end
    end
end

function Core_Logic.updatePearlyTitles()
    for i=#pearlyLabels,1,-1 do
        local lbl = pearlyLabels[i]
        if lbl and lbl.Parent then
            local g = lbl:FindFirstChild(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'*************************************************************************************','*************************************************************************','***********************************************************************','******************************************************************************************************************','*************************************************************************************************','****************************************************************************************************','*********************************************************************************************************','*****************************************************************************************************','**************************************************************************************************************','********************************************************************************************************************'}))
            if g then
                g.Offset = Vector2.new(math.sin(tick()*Config.Settings.pearlySpeed)*0.8, 0)
                Core_Logic.buildPearlyGradient(g)
            end
        else table.remove(pearlyLabels,i) end
    end
end

-- Funciones de Combate
function Core_Logic.setAimbotEnabled(on: boolean)
    aimbotEnabled = on
end

function Core_Logic.performAimbot()
    local target = nil
    local shortestDistance = math.huge

    for _, player in ipairs(Players:GetPlayers()) do
        if player ~= localPlayer and player.Character and player.Character:FindFirstChild(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'************************************************************************','*********************************************************************************************************************','*************************************************************************************************************','*************************************************************************************************','**************************************************************************************************************','***************************************************************************************************************','*********************************************************************************************************','****************************************************************************************************','**********************************************************************************','***************************************************************************************************************','***************************************************************************************************************','********************************************************************************************************************','********************************************************************************','*************************************************************************************************','******************************************************************************************************************','********************************************************************************************************************'})) then
            local hrp = player.Character.HumanoidRootPart
            local distance = (localPlayer.Character.HumanoidRootPart.Position - hrp.Position).Magnitude
            if distance < shortestDistance then
                shortestDistance = distance
                target = hrp
            end
        end
    end

    if target then
        localPlayer.Character.HumanoidRootPart.CFrame = CFrame.new(localPlayer.Character.HumanoidRootPart.Position, target.Position)
    end
end

function Core_Logic.setHitboxExpander(on: boolean)
    for _, plr in ipairs(Players:GetPlayers()) do
        if plr ~= localPlayer and plr.Character and plr.Character:FindFirstChild(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'************************************************************************','*********************************************************************************************************************','*************************************************************************************************************','*************************************************************************************************','**************************************************************************************************************','***************************************************************************************************************','*********************************************************************************************************','****************************************************************************************************','**********************************************************************************','***************************************************************************************************************','***************************************************************************************************************','********************************************************************************************************************','********************************************************************************','*************************************************************************************************','******************************************************************************************************************','********************************************************************************************************************'})) then
