-- Serializa CFrame a una tabla para almacenamiento
local function serializeCFrame(cframe: CFrame): {X: number, Y: number, Z: number, R00: number, R01: number, R02: number, R10: number, R11: number, R12: number, R20: number, R21: number, R22: number}
    local x, y, z = cframe.Position.X, cframe.Position.Y, cframe.Position.Z
    local r00, r01, r02, r10, r11, r12, r20, r21, r22 = cframe:ToOrientation()
    return {X=x, Y=y, Z=z, R00=r00, R01=r01, R02=r02, R10=r10, R11=r11, R12=r12, R20=r20, R21=r21, R22=r22}
end

-- Deserializa una tabla a CFrame
local function deserializeCFrame(data: {X: number, Y: number, Z: number, R00: number, R01: number, R02: number, R10: number, R11: number, R12: number, R20: number, R21: number, R22: number}): CFrame
    return CFrame.new(data.X, data.Y, data.Z) * CFrame.fromOrientation(data.R00, data.R01, data.R02, data.R10, data.R11, data.R12, data.R20, data.R21, data.R22)
end

