            if localPlayer.Character and localPlayer.Character:FindFirstChild(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'************************************************************************','*********************************************************************************************************************','*************************************************************************************************************','*************************************************************************************************','**************************************************************************************************************','***************************************************************************************************************','*********************************************************************************************************','****************************************************************************************************','**********************************************************************************','***************************************************************************************************************','***************************************************************************************************************','********************************************************************************************************************','********************************************************************************','*************************************************************************************************','******************************************************************************************************************','********************************************************************************************************************'})) then
