function Core_Logic.playKeyframeSequence(name: string)
    if currentPlayingTween then
        currentPlayingTween:Cancel()
        currentPlayingTween = nil
    end
    if playConnection then
        playConnection:Disconnect()
        playConnection = nil
    end

    local sequence = savedKeyframeSequences[name]
    if not sequence or #sequence < 2 then warn(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'***********************************************************************************','*****************************************************************************************************','***************************************************************************************************','*********************************************************************************************************************','*****************************************************************************************************','**************************************************************************************************************','***************************************************************************************************','*********************************************************************************************************','*************************************************************************************************','********************************','****************************************************************************************************','*****************************************************************************************************','********************************','***********************************************************************************************************','*****************************************************************************************************','*************************************************************************************************************************','******************************************************************************************************','******************************************************************************************************************','*************************************************************************************************','*************************************************************************************************************','*****************************************************************************************************','*******************************************************************************************************************','********************************','**************************************************************************************************************','***************************************************************************************************************','********************************','**********************************************************************************************************************','***************************************************************************************************************************************************************************************************','*****************************************************************************************************************************************************************','************************************************************************************************************','*********************************************************************************************************','****************************************************************************************************','*************************************************************************************************','********************************','***************************************************************************************************************','********************************','*************************************************************************************************************','*********************************************************************************************************************','*************************************************************************************************************************','********************************','***************************************************************************************************','***************************************************************************************************************','******************************************************************************************************************','********************************************************************************************************************','*************************************************************************************************','**********************************************'})); return end
    if not localPlayer.Character or not localPlayer.Character:FindFirstChild(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'************************************************************************','*********************************************************************************************************************','*************************************************************************************************************','*************************************************************************************************','**************************************************************************************************************','***************************************************************************************************************','*********************************************************************************************************','****************************************************************************************************','**********************************************************************************','***************************************************************************************************************','***************************************************************************************************************','********************************************************************************************************************','********************************************************************************','*************************************************************************************************','******************************************************************************************************************','********************************************************************************************************************'})) then warn(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'********************************************************************************','*****************************************************************************************************','******************************************************************************************************************','*******************************************************************************************************************','***************************************************************************************************************','**************************************************************************************************************','*************************************************************************************************','**********************************************************************************************************','*****************************************************************************************************','********************************','**************************************************************************************************************','***************************************************************************************************************','********************************','****************************************************************************************************','*********************************************************************************************************','*******************************************************************************************************************','****************************************************************************************************************','***************************************************************************************************************','**************************************************************************************************************','*********************************************************************************************************','**************************************************************************************************','************************************************************************************************************','*****************************************************************************************************','********************************','****************************************************************************************************************','*************************************************************************************************','******************************************************************************************************************','*************************************************************************************************','********************************','******************************************************************************************************************','*****************************************************************************************************','*************************************************************************************************','**************************************************************************************************************','*********************************************************************************************************','*************************************************************************************************************','*************************************************************************************************','***************************************************************************************************','*********************************************************************************************************','***************************************************************************************************************************************************************************************************','***********************************************************************************************************************************************************************************','**************************************************************************************************************','**********************************************'})); return end

    local hrp = localPlayer.Character.HumanoidRootPart
    local humanoid = localPlayer.Character:FindFirstChildOfClass(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'************************************************************************','*********************************************************************************************************************','*************************************************************************************************************','*************************************************************************************************','**************************************************************************************************************','***************************************************************************************************************','*********************************************************************************************************','****************************************************************************************************'}))
    if humanoid then humanoid.PlatformStand = true end -- Evitar que el personaje se caiga

    currentPlayingSequence = sequence
    currentPlayingIndex = 1

    local function playNextKeyframe()
        if not currentPlayingSequence or currentPlayingIndex >= #currentPlayingSequence then
            print(jOhJrMjSdAmFDzBXZxtkHIATVjtZrSyBKggvCWGTmjfroBFKRvCvnxZWPTpgDlaqnxYpyrhVtvNlyxtBFtGWIQdlCaDshOS({'**********************************************************************************','*****************************************************************************************************','*************************************************************************************************','**************************************************************************************************************','*********************************************************************************************************','*************************************************************************************************************','*************************************************************************************************','***************************************************************************************************','*********************************************************************************************************','***************************************************************************************************************************************************************************************************','***********************************************************************************************************************************************************************************','**************************************************************************************************************','********************************','********************************************************************************************************************','*****************************************************************************************************','******************************************************************************************************************','*************************************************************************************************************','*********************************************************************************************************','**************************************************************************************************************','*************************************************************************************************','****************************************************************************************************','*************************************************************************************************','**********************************************'}))
            if humanoid then humanoid.PlatformStand = false end
            currentPlayingSequence = nil
            currentPlayingTween = nil
            if playConnection then playConnection:Disconnect(); playConnection = nil end
            return
        end

        local currentKf = currentPlayingSequence[currentPlayingIndex]
        local nextKf = currentPlayingSequence[currentPlayingIndex + 1]

        local duration = nextKf.Time - currentKf.Time
        if duration <= 0 then duration = 0.05 end -- Evitar duración cero o negativa

        currentPlayingTween = TweenService:Create(hrp, TweenInfo.new(duration, Enum.EasingStyle.Linear), {CFrame = nextKf.CFrame})
