    local dragStart = Vector2.new(0,0)
    local initialPos = UDim2.new(0,0,0,0)

    topBar.InputBegan:Connect(function(input: InputObject)
        if input.UserInputType == Enum.UserInputType.MouseButton1 then
            dragging = true
            dragStart = input.Position
            initialPos = mainFrame.Position
        end
    end)

    UserInputService.InputChanged:Connect(function(input: InputObject)
        if dragging and input.UserInputType == Enum.UserInputType.MouseMovement then
            local delta = input.Position - dragStart
            mainFrame.Position = UDim2.new(
                initialPos.X.Scale, initialPos.X.Offset + delta.X,
                initialPos.Y.Scale, initialPos.Y.Offset + delta.Y
            )
        end
    end)

    UserInputService.InputEnded:Connect(function(input: InputObject)
        if input.UserInputType == Enum.UserInputType.MouseButton1 then
            dragging = false
        end
    end)
