function Main_UI.setPanelVisibility(visible: boolean)
    if visible then
        mainFrame.Visible = true
        UI_Utils.makeTween(mainFrame, {BackgroundTransparency = 0, Size = UDim2.new(0, 700, 0, 500)}, 0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out):Play()
    else
        UI_Utils.makeTween(mainFrame, {BackgroundTransparency = 1, Size = UDim2.new(0, 650, 0, 450)}, 0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.In):Play()
        task.delay(0.3, function() mainFrame.Visible = false end)
    end
end

function Main_UI.setProfilePicture(imageUrl: string)
    if profilePictureImage then
        profilePictureImage.Image = imageUrl
    end
end

